import{_ as a,a as i,b as t,c as o}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as l,o as n,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Aggiungere un canale S3","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/s3.md","filePath":"it-IT/upload/s3.md","lastUpdated":1781962217000}'),r={name:"it-IT/upload/s3.md"};function c(p,e,u,h,m,g){return n(),s("div",null,[...e[0]||(e[0]=[d(`<h1 id="aggiungere-un-canale-s3" tabindex="-1">Aggiungere un canale S3 <a class="header-anchor" href="#aggiungere-un-canale-s3" aria-label="Permalink to &quot;Aggiungere un canale S3&quot;">​</a></h1><h2 id="quando-usarlo" tabindex="-1">Quando usarlo <a class="header-anchor" href="#quando-usarlo" aria-label="Permalink to &quot;Quando usarlo&quot;">​</a></h2><p>Usa il canale S3 quando:</p><ul><li>vuoi collegare un servizio di object storage compatibile S3, come Cloudflare R2, Backblaze B2, MinIO, AWS S3 o altri provider compatibili.</li><li>preferisci la configurazione S3 standard con <code>Endpoint</code>, Access Key e Secret Key.</li><li>non vuoi usare il canale nativo Cloudflare R2 tramite binding, oppure il tuo provider non è Cloudflare R2.</li></ul><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>A cosa serve</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>Endpoint API S3 del servizio di archiviazione.</td></tr><tr><td>Nome bucket</td><td>Bucket in cui verranno salvati i file.</td></tr><tr><td>Region</td><td>Regione dello storage. Per Cloudflare R2 di solito è <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>ID della chiave di accesso S3.</td></tr><tr><td>Secret Access Key</td><td>Chiave segreta S3.</td></tr><tr><td>Dominio CDN</td><td>Dominio personalizzato opzionale per accedere ai file.</td></tr></tbody></table><p>Esempio per Cloudflare R2 tramite API S3:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copiato dal token API Cloudflare R2</span></span>
<span class="line"><span>Secret Access Key: copiato dal token API Cloudflare R2</span></span></code></pre></div><h2 id="dove-aggiungerlo" tabindex="-1">Dove aggiungerlo <a class="header-anchor" href="#dove-aggiungerlo" aria-label="Permalink to &quot;Dove aggiungerlo&quot;">​</a></h2><ol><li>Apri Impostazioni di sistema.</li><li>Vai a Impostazioni di caricamento.</li><li>Clicca su Aggiungi canale in alto a destra.</li><li>Seleziona <code>S3</code>.</li></ol><h2 id="riferimento-campi" tabindex="-1">Riferimento campi <a class="header-anchor" href="#riferimento-campi" aria-label="Permalink to &quot;Riferimento campi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Funzione</th><th>Obbligatorio</th></tr></thead><tbody><tr><td>Nome canale</td><td>Nome riconoscibile, per esempio <code>s3test</code> o <code>R2-S3</code>.</td><td>Sì</td></tr><tr><td>Abilita canale</td><td>Decide se il canale partecipa alla scelta dell&#39;upload.</td><td>Consigliato</td></tr><tr><td>Endpoint</td><td>Endpoint S3 completo, incluso <code>https://</code>.</td><td>Sì</td></tr><tr><td>Dominio CDN personalizzato</td><td>Opzionale. Se presente, i link generati useranno preferibilmente questo dominio.</td><td>No</td></tr><tr><td>Nome bucket</td><td>Nome del bucket, per esempio <code>s3test</code> o <code>img-r2</code>.</td><td>Sì</td></tr><tr><td>Regione bucket</td><td>Regione. Per Cloudflare R2 di solito è <code>auto</code>.</td><td>Sì</td></tr><tr><td>Access Key ID</td><td>ID della chiave S3.</td><td>Sì</td></tr><tr><td>Secret Access Key</td><td>Chiave segreta S3.</td><td>Sì</td></tr><tr><td>Path-style access</td><td>Opzione di compatibilità, disattivata di default. Alcuni servizi MinIO, OpenList o S3 self-hosted possono richiederla.</td><td>No</td></tr><tr><td>Limite quota</td><td>Decide se il canale viene scelto in base alla capacità.</td><td>No</td></tr><tr><td>Limite capacità</td><td>Richiesto dopo aver attivato il limite quota, per esempio <code>10 GB</code>.</td><td>Obbligatorio con limite quota</td></tr><tr><td>Soglia</td><td>Ferma le scritture quando l&#39;uso raggiunge questa percentuale, per esempio <code>90%</code>.</td><td>Obbligatorio con limite quota</td></tr><tr><td>Nota</td><td>Appunti per la manutenzione.</td><td>No</td></tr></tbody></table><h2 id="creare-chiavi-s3-api-per-cloudflare-r2" tabindex="-1">Creare chiavi S3 API per Cloudflare R2 <a class="header-anchor" href="#creare-chiavi-s3-api-per-cloudflare-r2" aria-label="Permalink to &quot;Creare chiavi S3 API per Cloudflare R2&quot;">​</a></h2><ol><li>Apri la dashboard Cloudflare.</li><li>Vai a <code>R2 Object Storage</code>.</li><li>Trova <code>Manage R2 API Tokens</code> o la voce per gestire i token API.</li></ol><p>![Voce token API R2](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Crea un token API R2 con accesso al bucket di destinazione.</li></ol><p><img src="`+a+'" alt="Crea token API account" loading="lazy"></p><ol start="5"><li>Copia <code>Access Key ID</code> e <code>Secret Access Key</code>.</li></ol><p><img src="'+i+'" alt="Copia valori token" loading="lazy"></p><ol start="6"><li>Torna alla pagina del bucket R2 e conferma il nome del bucket.</li><li>Annota l&#39;endpoint API S3 dell&#39;account. Di solito ha questo formato:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="passaggi-di-configurazione" tabindex="-1">Passaggi di configurazione <a class="header-anchor" href="#passaggi-di-configurazione" aria-label="Permalink to &quot;Passaggi di configurazione&quot;">​</a></h2><ol><li>Apri Impostazioni di caricamento.</li><li>Clicca su Aggiungi canale.</li><li>Seleziona <code>S3</code>.</li><li>Inserisci un nome canale chiaro, per esempio <code>s3test</code>.</li><li>Inserisci l&#39;endpoint API S3 in <code>Endpoint</code>.</li><li>Se usi un CDN personalizzato, inseriscilo in <code>Custom CDN domain</code>; altrimenti lascia vuoto.</li><li>Inserisci il nome del bucket.</li><li>Inserisci la region. Nell&#39;esempio Cloudflare R2 usa <code>auto</code>.</li><li>Inserisci Access Key ID e Secret Access Key.</li><li>Lascia Path-style access disattivato, salvo richiesta esplicita del provider.</li><li>Se vuoi il controllo della capacità, abilita il limite quota e inserisci limite e soglia.</li><li>Salva.</li></ol><p><img src="'+t+'" alt="Aggiungi configurazione S3" loading="lazy"></p><h2 id="verifica" tabindex="-1">Verifica <a class="header-anchor" href="#verifica" aria-label="Permalink to &quot;Verifica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controllo</th><th>Come verificare</th></tr></thead><tbody><tr><td>Scheda canale</td><td>Dopo il salvataggio compare una scheda S3 nelle Impostazioni di caricamento.</td></tr><tr><td>Canale attivo</td><td>L&#39;interruttore in alto a destra della scheda resta acceso.</td></tr><tr><td>Campi salvati</td><td>La vista dettaglio mostra Endpoint, Bucket, Region, Path-style access e campi collegati.</td></tr><tr><td>Upload funzionante</td><td>Carica un&#39;immagine di prova e verifica che l&#39;oggetto compaia nel bucket.</td></tr><tr><td>Link apribile</td><td>Il link restituito dopo l&#39;upload si apre normalmente.</td></tr><tr><td>Capacità visibile</td><td>Se il limite quota è attivo, la scheda mostra capacità usata e limite configurato.</td></tr></tbody></table><p>Le statistiche di capacità S3 sono calcolate dai record locali dei file in ImgBed, non interrogando il bucket del provider in tempo reale. Dopo il salvataggio, il sistema ricalcola il riepilogo quote dai record D1 attuali.</p><p><img src="'+o+`" alt="Quota interrogata correttamente" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="devo-attivare-path-style-access" tabindex="-1">Devo attivare Path-style access? <a class="header-anchor" href="#devo-attivare-path-style-access" aria-label="Permalink to &quot;Devo attivare Path-style access?&quot;">​</a></h3><p>Di solito no.</p><p>Attivalo solo se il provider S3 compatibile non supporta URL virtual-hosted-style o se la documentazione lo richiede. Alcuni endpoint MinIO, S3 self-hosted e compatibili OpenList possono averne bisogno.</p><h3 id="a-cosa-serve-il-dominio-cdn" tabindex="-1">A cosa serve il dominio CDN? <a class="header-anchor" href="#a-cosa-serve-il-dominio-cdn" aria-label="Permalink to &quot;A cosa serve il dominio CDN?&quot;">​</a></h3><p>Se metti un CDN o un dominio di accesso personalizzato davanti al bucket, inseriscilo qui.</p><p>Dopo la configurazione, ImgBed preferirà quel dominio nei link generati. Se non usi un CDN, lascia il campo vuoto.</p><h3 id="perche-l-upload-fallisce" tabindex="-1">Perché l&#39;upload fallisce? <a class="header-anchor" href="#perche-l-upload-fallisce" aria-label="Permalink to &quot;Perché l&#39;upload fallisce?&quot;">​</a></h3><p>Controlla prima questi punti:</p><ol><li>L&#39;Endpoint include l&#39;URL completo con <code>https://</code>.</li><li>Il nome del bucket è corretto.</li><li>La Region corrisponde ai requisiti del provider.</li><li>Access Key ID e Secret Access Key sono stati copiati integralmente.</li><li>La chiave ha permesso di scrittura sul bucket di destinazione.</li><li>Il provider non richiede Path-style access, oppure l&#39;opzione è stata attivata se necessaria.</li></ol><h2 id="checklist-rapida" tabindex="-1">Checklist rapida <a class="header-anchor" href="#checklist-rapida" aria-label="Permalink to &quot;Checklist rapida&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Prepara S3 Endpoint, Bucket, Region, Access Key e Secret Key</span></span>
<span class="line"><span>-&gt; Apri Impostazioni di caricamento</span></span>
<span class="line"><span>-&gt; Aggiungi canale</span></span>
<span class="line"><span>-&gt; Seleziona S3</span></span>
<span class="line"><span>-&gt; Inserisci Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; Inserisci un dominio CDN se serve</span></span>
<span class="line"><span>-&gt; Lascia Path-style access disattivato di default</span></span>
<span class="line"><span>-&gt; Abilita il limite quota se serve</span></span>
<span class="line"><span>-&gt; Salva</span></span>
<span class="line"><span>-&gt; Carica un&#39;immagine di prova e controlla il risultato</span></span></code></pre></div>`,40)])])}const S=l(r,[["render",c]]);export{f as __pageData,S as default};
